package com.example.recipe_generator.presentation.home
import androidx.compose.foundation.layout.* import androidx.compose.material.icons.Icons import androidx.compose.material.icons.filled.ExitToApp import androidx.compose.material3.* import androidx.compose.runtime.Composable import androidx.compose.ui.Alignment import androidx.compose.ui.Modifier import androidx.compose.ui.text.style.TextAlign import androidx.compose.ui.unit.dp import androidx.compose.ui.unit.sp
/** * Pantalla principal de la app (después de autenticarse) * Muestra: * - Bienvenida al usuario * - Botón de logout * - Placeholder para futuro contenido */ @Composable fun HomeScreen( userEmail: String, onLogout: () -> Unit ) { Column( modifier = Modifier .fillMaxSize() .padding(16.dp), horizontalAlignment = Alignment.CenterHorizontally, verticalArrangement = Arrangement.spacedBy(16.dp) ) { // Header Text( text = "¡Bienvenido!", fontSize = 32.sp, style = MaterialTheme.typography.headlineLarge, color = MaterialTheme.colorScheme.primary, modifier = Modifier.padding(top = 24.dp) )
// User info Card( modifier = Modifier .fillMaxWidth() .padding(8.dp), colors = CardDefaults.cardColors( containerColor = MaterialTheme.colorScheme.secondaryContainer ) ) { Column( modifier = Modifier .fillMaxWidth() .padding(16.dp), horizontalAlignment = Alignment.CenterHorizontally ) { Text( text = "Usuario Autenticado", fontSize = 14.sp, color = MaterialTheme.colorScheme.onSecondaryContainer ) Spacer(modifier = Modifier.height(8.dp)) Text( text = userEmail, fontSize = 16.sp, fontWeight = androidx.compose.ui.text.font.FontWeight.Bold, color = MaterialTheme.colorScheme.onSecondaryContainer, textAlign = TextAlign.Center, modifier = Modifier.fillMaxWidth() ) } }
// Divider Divider(modifier = Modifier.padding(vertical = 16.dp))
// Content placeholder Card( modifier = Modifier .fillMaxWidth() .weight(1f) .padding(8.dp), colors = CardDefaults.cardColors( containerColor = MaterialTheme.colorScheme.tertiary.copy(alpha = 0.1f) ) ) { Column( modifier = Modifier .fillMaxSize() .padding(24.dp), horizontalAlignment = Alignment.CenterHorizontally, verticalArrangement = Arrangement.Center ) { Text( text = "", fontSize = 48.sp, modifier = Modifier.padding(16.dp) ) Text( text = "Próximamente", fontSize = 18.sp, style = MaterialTheme.typography.titleMedium ) Spacer(modifier = Modifier.height(8.dp)) Text( text = "Tu contenido personalizado aparecerá aquí", fontSize = 14.sp, color = MaterialTheme.colorScheme.onSurfaceVariant, textAlign = TextAlign.Center ) } }
// Logout button Button( onClick = onLogout, modifier = Modifier .fillMaxWidth() .height(48.dp) .padding(horizontal = 8.dp), colors = ButtonDefaults.buttonColors( containerColor = MaterialTheme.colorScheme.error ) ) { Icon( imageVector = Icons.Default.ExitToApp, contentDescription = "Logout", modifier = Modifier.size(20.dp), tint = MaterialTheme.colorScheme.onError ) Spacer(modifier = Modifier.width(8.dp)) Text( text = "Cerrar Sesión", fontSize = 16.sp, color = MaterialTheme.colorScheme.onError ) } } }

